func maxInt64(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}

func cashH(cents int64, all []store.MonthCashflow) float64 {
	var max int64
	for _, r := range all {
		if r.IncomeCents > max {
			max = r.IncomeCents
		}
		if r.OutflowCents > max {
			max = r.OutflowCents
		}
	}
	if max == 0 {
		return 0
	}
	return float64(cents) / float64(max) * 250
}

func monthShort(month string) string {
	t, err := time.Parse("2006-01", month)
	if err != nil {
		return month
	}
	return t.Format("Jan")
}

func formatMonthFull(month string) string {
	t, err := time.Parse("2006-01", month)
	if err != nil {
		return month
	}
	return t.Format("Jan 2006")
}

